-- Finance Phase 5: country economies, national treasuries and jurisdiction-backed taxation.
-- Baseline indices use 100 as the documented neutral value. All tax calculations are derived
-- from financial_transactions/financial_ledger_entries and all cash movement uses finance_transfer.

ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'national_tax_payment';
ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'national_tax_refund';
ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'payroll_tax_withholding';
ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'employer_payroll_contribution';
ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'sales_tax_remittance';
ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'government_grant_payment';
ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'national_budget_spend';
ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'national_treasury_adjustment';

DO $$ BEGIN CREATE TYPE public.country_economic_scale AS ENUM ('small','medium','large','major','global'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.country_economic_profile_type AS ENUM ('low_cost_growth_market','mature_high_cost_market','tourism_led_economy','creative_industry_hub','manufacturing_led_economy','service_led_economy','emerging_music_market','highly_regulated_market'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.country_economic_trend AS ENUM ('strong_growth','growth','stable','slowing','decline','severe_decline'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.tax_jurisdiction_status AS ENUM ('draft','active','superseded','archived'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.tax_entity_type AS ENUM ('player','band','company','venue','festival_organisation','trust','city_government','national_government'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.tax_registration_status AS ENUM ('draft','active','under_review','ended','suspended'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.tax_period_frequency AS ENUM ('per_payroll','weekly','monthly','quarterly','annual','custom'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.tax_period_status AS ENUM ('open','calculating','estimated','ready_to_file','filed','payment_due','partially_paid','paid','refund_due','refunded','overdue','adjusted','under_review','closed'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.tax_type AS ENUM ('personal_income','band_income','corporation','payroll_withholding','employer_payroll_contribution','sales_tax','vat'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.tax_assessment_status AS ENUM ('estimate','draft','finalised','filed','payment_due','partially_paid','paid','refund_due','refunded','overdue','adjusted','replaced','cancelled'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.band_tax_treatment AS ENUM ('pass_through','taxed_entity','hybrid'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.tax_timing_basis AS ENUM ('cash','accrual','withholding_event','sale_event'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.tax_jurisdiction_source AS ENUM ('tax_residence','registration_country','headquarters_country','transaction_location','seller_location','buyer_location','configured_default'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

CREATE TABLE IF NOT EXISTS public.country_economic_profiles (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(), country_name text NOT NULL, country_code text NOT NULL UNIQUE, primary_currency_code char(3) NOT NULL DEFAULT 'USD', population_placeholder bigint NOT NULL DEFAULT 1000000,
  economic_size bigint NOT NULL DEFAULT 1000000, economic_scale public.country_economic_scale NOT NULL DEFAULT 'medium', economic_profile public.country_economic_profile_type NOT NULL DEFAULT 'service_led_economy',
  prosperity_index integer NOT NULL DEFAULT 100 CHECK (prosperity_index BETWEEN 1 AND 250), national_cost_index integer NOT NULL DEFAULT 100 CHECK (national_cost_index BETWEEN 1 AND 250), national_wage_index integer NOT NULL DEFAULT 100 CHECK (national_wage_index BETWEEN 1 AND 250), consumer_spending_index integer NOT NULL DEFAULT 100 CHECK (consumer_spending_index BETWEEN 1 AND 250), business_confidence_index integer NOT NULL DEFAULT 100 CHECK (business_confidence_index BETWEEN 1 AND 250), tourism_index integer NOT NULL DEFAULT 100 CHECK (tourism_index BETWEEN 1 AND 250), infrastructure_index integer NOT NULL DEFAULT 100 CHECK (infrastructure_index BETWEEN 1 AND 250), music_industry_index integer NOT NULL DEFAULT 100 CHECK (music_industry_index BETWEEN 1 AND 250), employment_index integer NOT NULL DEFAULT 100 CHECK (employment_index BETWEEN 1 AND 250), inflation_index_placeholder integer NOT NULL DEFAULT 100 CHECK (inflation_index_placeholder BETWEEN 1 AND 250), interest_rate_placeholder_basis_points integer NOT NULL DEFAULT 300 CHECK (interest_rate_placeholder_basis_points BETWEEN 0 AND 10000), tax_burden_index integer NOT NULL DEFAULT 100 CHECK (tax_burden_index BETWEEN 1 AND 250), government_spending_index integer NOT NULL DEFAULT 100 CHECK (government_spending_index BETWEEN 1 AND 250), economic_trend public.country_economic_trend NOT NULL DEFAULT 'stable', default_tax_jurisdiction_id uuid, last_calculated_at timestamptz, configuration_metadata jsonb NOT NULL DEFAULT '{"baseline":100,"balance_note":"fictionalised gameplay-balanced indices"}'::jsonb, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc',now())
);

CREATE TABLE IF NOT EXISTS public.national_treasury_profiles (
  country_profile_id uuid PRIMARY KEY REFERENCES public.country_economic_profiles(id) ON DELETE CASCADE, treasury_account_id uuid NOT NULL UNIQUE REFERENCES public.financial_accounts(id), currency_code char(3) NOT NULL DEFAULT 'USD', tax_revenue_minor bigint NOT NULL DEFAULT 0, fee_revenue_minor bigint NOT NULL DEFAULT 0, transfers_received_minor bigint NOT NULL DEFAULT 0, grants_paid_minor bigint NOT NULL DEFAULT 0, city_transfers_minor bigint NOT NULL DEFAULT 0, government_spending_minor bigint NOT NULL DEFAULT 0, refunds_minor bigint NOT NULL DEFAULT 0, outstanding_commitments_minor bigint NOT NULL DEFAULT 0, financial_status text NOT NULL DEFAULT 'stable', public_summary_enabled boolean NOT NULL DEFAULT true, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc',now())
);

CREATE TABLE IF NOT EXISTS public.tax_jurisdictions (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(), country_profile_id uuid NOT NULL REFERENCES public.country_economic_profiles(id) ON DELETE CASCADE, jurisdiction_name text NOT NULL, jurisdiction_code text NOT NULL UNIQUE, currency_code char(3) NOT NULL DEFAULT 'USD', effective_start_date date NOT NULL DEFAULT CURRENT_DATE, effective_end_date date, status public.tax_jurisdiction_status NOT NULL DEFAULT 'draft', personal_tax_config jsonb NOT NULL DEFAULT '{}', band_tax_config jsonb NOT NULL DEFAULT '{"treatment":"pass_through","allocation_method":"membership_duration"}', company_tax_config jsonb NOT NULL DEFAULT '{}', payroll_config jsonb NOT NULL DEFAULT '{"withholding_enabled":true,"employer_contribution_basis_points":200}', sales_tax_config jsonb NOT NULL DEFAULT '{"settlement_model":"immediate_remittance","pricing":"exclusive"}', withholding_config jsonb NOT NULL DEFAULT '{}', filing_calendar jsonb NOT NULL DEFAULT '{"personal":"annual","corporation":"quarterly","sales_tax":"immediate","payroll":"per_payroll"}', grace_periods jsonb NOT NULL DEFAULT '{"filing_days":14,"payment_days":14}', penalty_config_placeholder jsonb NOT NULL DEFAULT '{}', rounding_rules jsonb NOT NULL DEFAULT '{"mode":"nearest_minor_unit","half":"up"}', metadata jsonb NOT NULL DEFAULT '{}', created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc',now()), CONSTRAINT tax_jurisdiction_dates CHECK (effective_end_date IS NULL OR effective_end_date >= effective_start_date)
);
CREATE UNIQUE INDEX IF NOT EXISTS tax_one_active_default_jurisdiction_idx ON public.tax_jurisdictions(country_profile_id) WHERE status='active' AND effective_end_date IS NULL;
ALTER TABLE public.country_economic_profiles ADD CONSTRAINT country_default_tax_jurisdiction_fk FOREIGN KEY (default_tax_jurisdiction_id) REFERENCES public.tax_jurisdictions(id) DEFERRABLE INITIALLY DEFERRED;

CREATE TABLE IF NOT EXISTS public.tax_entity_registrations (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), entity_type public.tax_entity_type NOT NULL, entity_id uuid NOT NULL, jurisdiction_id uuid NOT NULL REFERENCES public.tax_jurisdictions(id), effective_start date NOT NULL DEFAULT CURRENT_DATE, effective_end date, registration_status public.tax_registration_status NOT NULL DEFAULT 'active', tax_identifier text NOT NULL DEFAULT ('TAX-' || upper(substr(gen_random_uuid()::text,1,12))), residency_basis text NOT NULL, last_reviewed_at timestamptz, metadata jsonb NOT NULL DEFAULT '{}', created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), UNIQUE(entity_type, entity_id, jurisdiction_id, effective_start), CONSTRAINT tax_registration_dates CHECK (effective_end IS NULL OR effective_end >= effective_start));
CREATE UNIQUE INDEX IF NOT EXISTS tax_active_entity_registration_idx ON public.tax_entity_registrations(entity_type, entity_id) WHERE registration_status='active' AND effective_end IS NULL;

CREATE TABLE IF NOT EXISTS public.tax_transaction_classifications (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), transaction_category public.financial_transaction_category NOT NULL, tax_category text NOT NULL, affected_entity_types public.tax_entity_type[] NOT NULL, is_taxable boolean NOT NULL DEFAULT false, income_or_expense_treatment text NOT NULL CHECK (income_or_expense_treatment IN ('income','expense','capital','transfer','excluded')), deductibility text NOT NULL DEFAULT 'none', withholding_eligible boolean NOT NULL DEFAULT false, sales_tax_treatment text NOT NULL DEFAULT 'out_of_scope', timing_basis public.tax_timing_basis NOT NULL DEFAULT 'cash', jurisdiction_source public.tax_jurisdiction_source NOT NULL DEFAULT 'configured_default', reporting_label text NOT NULL, effective_start_date date NOT NULL DEFAULT CURRENT_DATE, effective_end_date date, metadata jsonb NOT NULL DEFAULT '{}', UNIQUE(transaction_category, effective_start_date));

CREATE TABLE IF NOT EXISTS public.personal_income_tax_brackets (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), jurisdiction_id uuid NOT NULL REFERENCES public.tax_jurisdictions(id) ON DELETE CASCADE, effective_start_date date NOT NULL DEFAULT CURRENT_DATE, effective_end_date date, lower_bound_minor bigint NOT NULL CHECK (lower_bound_minor >= 0), upper_bound_minor bigint, tax_rate_basis_points integer NOT NULL CHECK (tax_rate_basis_points BETWEEN 0 AND 10000), bracket_order integer NOT NULL, allowance_interaction text NOT NULL DEFAULT 'after_allowance', status public.tax_jurisdiction_status NOT NULL DEFAULT 'active', UNIQUE(jurisdiction_id,effective_start_date,bracket_order), CONSTRAINT personal_tax_bracket_bounds CHECK (upper_bound_minor IS NULL OR upper_bound_minor > lower_bound_minor));
CREATE TABLE IF NOT EXISTS public.personal_tax_allowances (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), jurisdiction_id uuid NOT NULL REFERENCES public.tax_jurisdictions(id) ON DELETE CASCADE, allowance_type text NOT NULL, amount_minor bigint NOT NULL DEFAULT 0 CHECK(amount_minor>=0), phaseout_config jsonb NOT NULL DEFAULT '{}', effective_start_date date NOT NULL DEFAULT CURRENT_DATE, effective_end_date date, status public.tax_jurisdiction_status NOT NULL DEFAULT 'active', metadata jsonb NOT NULL DEFAULT '{}', UNIQUE(jurisdiction_id, allowance_type, effective_start_date));
CREATE TABLE IF NOT EXISTS public.corporation_tax_rules (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), jurisdiction_id uuid NOT NULL REFERENCES public.tax_jurisdictions(id) ON DELETE CASCADE, effective_start_date date NOT NULL DEFAULT CURRENT_DATE, effective_end_date date, flat_rate_basis_points integer NOT NULL DEFAULT 2000 CHECK(flat_rate_basis_points BETWEEN 0 AND 10000), small_profit_rate_basis_points integer, small_profit_threshold_minor bigint, standard_rate_basis_points integer, startup_allowance_minor bigint NOT NULL DEFAULT 0, loss_carry_forward_enabled boolean NOT NULL DEFAULT true, status public.tax_jurisdiction_status NOT NULL DEFAULT 'active', metadata jsonb NOT NULL DEFAULT '{}');
CREATE TABLE IF NOT EXISTS public.company_tax_losses (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), company_id uuid NOT NULL REFERENCES public.companies(id) ON DELETE CASCADE, jurisdiction_id uuid NOT NULL REFERENCES public.tax_jurisdictions(id), tax_period_id uuid, current_period_loss_minor bigint NOT NULL DEFAULT 0, carried_forward_loss_minor bigint NOT NULL DEFAULT 0, loss_used_minor bigint NOT NULL DEFAULT 0, remaining_loss_minor bigint NOT NULL DEFAULT 0, expiry_placeholder date, adjustment_history jsonb NOT NULL DEFAULT '[]', created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), UNIQUE(company_id,jurisdiction_id,tax_period_id));
CREATE TABLE IF NOT EXISTS public.sales_tax_rules (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), jurisdiction_id uuid NOT NULL REFERENCES public.tax_jurisdictions(id) ON DELETE CASCADE, effective_start_date date NOT NULL DEFAULT CURRENT_DATE, effective_end_date date, tax_style text NOT NULL DEFAULT 'sales_tax' CHECK(tax_style IN ('sales_tax','vat')), pricing_mode text NOT NULL DEFAULT 'exclusive' CHECK(pricing_mode IN ('inclusive','exclusive')), standard_rate_basis_points integer NOT NULL DEFAULT 800 CHECK(standard_rate_basis_points BETWEEN 0 AND 10000), reduced_rate_basis_points integer NOT NULL DEFAULT 400 CHECK(reduced_rate_basis_points BETWEEN 0 AND 10000), zero_rated_categories text[] NOT NULL DEFAULT '{}', exempt_categories text[] NOT NULL DEFAULT '{}', taxable_categories text[] NOT NULL DEFAULT ARRAY['equipment_purchase','merchandise_revenue','recording_studio_payment','rehearsal_payment','ticket_sale','product_sale','service_sale'], city_allocation_basis_points integer NOT NULL DEFAULT 0 CHECK(city_allocation_basis_points BETWEEN 0 AND 10000), status public.tax_jurisdiction_status NOT NULL DEFAULT 'active', metadata jsonb NOT NULL DEFAULT '{}');

CREATE TABLE IF NOT EXISTS public.tax_periods (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), entity_type public.tax_entity_type NOT NULL, entity_id uuid NOT NULL, jurisdiction_id uuid NOT NULL REFERENCES public.tax_jurisdictions(id), tax_type public.tax_type NOT NULL, period_start date NOT NULL, period_end date NOT NULL, filing_due_date date NOT NULL, payment_due_date date NOT NULL, status public.tax_period_status NOT NULL DEFAULT 'open', calculation_version integer NOT NULL DEFAULT 1, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), finalised_at timestamptz, metadata jsonb NOT NULL DEFAULT '{}', UNIQUE(entity_type,entity_id,jurisdiction_id,tax_type,period_start,period_end), CONSTRAINT tax_period_dates CHECK(period_end >= period_start));
CREATE TABLE IF NOT EXISTS public.tax_assessments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), entity_type public.tax_entity_type NOT NULL, entity_id uuid NOT NULL, jurisdiction_id uuid NOT NULL REFERENCES public.tax_jurisdictions(id), tax_type public.tax_type NOT NULL, tax_period_id uuid NOT NULL REFERENCES public.tax_periods(id), gross_taxable_amount_minor bigint NOT NULL DEFAULT 0, allowances_minor bigint NOT NULL DEFAULT 0, deductions_minor bigint NOT NULL DEFAULT 0, adjusted_taxable_amount_minor bigint NOT NULL DEFAULT 0, calculated_tax_minor bigint NOT NULL DEFAULT 0, withheld_tax_minor bigint NOT NULL DEFAULT 0, prior_payments_minor bigint NOT NULL DEFAULT 0, credits_minor bigint NOT NULL DEFAULT 0, penalties_placeholder_minor bigint NOT NULL DEFAULT 0, interest_placeholder_minor bigint NOT NULL DEFAULT 0, refunds_minor bigint NOT NULL DEFAULT 0, final_amount_due_minor bigint NOT NULL DEFAULT 0, refund_due_minor bigint NOT NULL DEFAULT 0, calculation_breakdown jsonb NOT NULL DEFAULT '{}', calculation_version integer NOT NULL DEFAULT 1, status public.tax_assessment_status NOT NULL DEFAULT 'draft', created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), finalised_at timestamptz, replaced_by_assessment_id uuid REFERENCES public.tax_assessments(id));
CREATE UNIQUE INDEX IF NOT EXISTS tax_one_final_assessment_idx ON public.tax_assessments(tax_period_id) WHERE status IN ('finalised','filed','payment_due','partially_paid','paid','refund_due','refunded','overdue');
CREATE TABLE IF NOT EXISTS public.tax_payments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), assessment_id uuid NOT NULL REFERENCES public.tax_assessments(id), payer_entity_type public.tax_entity_type NOT NULL, payer_entity_id uuid NOT NULL, treasury_country_profile_id uuid NOT NULL REFERENCES public.country_economic_profiles(id), amount_minor bigint NOT NULL CHECK(amount_minor>0), transaction_id uuid UNIQUE REFERENCES public.financial_transactions(id), idempotency_key text NOT NULL UNIQUE, status text NOT NULL DEFAULT 'completed', receipt_reference text NOT NULL DEFAULT ('RCPT-' || upper(substr(gen_random_uuid()::text,1,12))), created_at timestamptz NOT NULL DEFAULT timezone('utc',now()));
CREATE TABLE IF NOT EXISTS public.tax_refunds (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), assessment_id uuid NOT NULL REFERENCES public.tax_assessments(id), recipient_entity_type public.tax_entity_type NOT NULL, recipient_entity_id uuid NOT NULL, treasury_country_profile_id uuid NOT NULL REFERENCES public.country_economic_profiles(id), amount_minor bigint NOT NULL CHECK(amount_minor>0), transaction_id uuid UNIQUE REFERENCES public.financial_transactions(id), idempotency_key text NOT NULL UNIQUE, status text NOT NULL DEFAULT 'approved', created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), paid_at timestamptz);
CREATE TABLE IF NOT EXISTS public.tax_statement_lines (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), assessment_id uuid NOT NULL REFERENCES public.tax_assessments(id) ON DELETE CASCADE, reporting_label text NOT NULL, transaction_category public.financial_transaction_category, gross_amount_minor bigint NOT NULL DEFAULT 0, taxable_amount_minor bigint NOT NULL DEFAULT 0, deductible_amount_minor bigint NOT NULL DEFAULT 0, withheld_amount_minor bigint NOT NULL DEFAULT 0, explanation text NOT NULL, source_transaction_ids uuid[] NOT NULL DEFAULT '{}', created_at timestamptz NOT NULL DEFAULT timezone('utc',now()));
CREATE TABLE IF NOT EXISTS public.band_tax_allocations (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), band_id uuid NOT NULL REFERENCES public.bands(id) ON DELETE CASCADE, member_profile_id uuid NOT NULL REFERENCES public.profiles(id), tax_period_id uuid NOT NULL REFERENCES public.tax_periods(id), allocation_basis text NOT NULL DEFAULT 'membership_duration', taxable_profit_allocated_minor bigint NOT NULL DEFAULT 0, cash_moved boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), UNIQUE(band_id,member_profile_id,tax_period_id));
CREATE TABLE IF NOT EXISTS public.tax_audit_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), actor_profile_id uuid REFERENCES public.profiles(id), action text NOT NULL, entity_type text NOT NULL, entity_id uuid, previous_value jsonb, new_value jsonb, reason text, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), metadata jsonb NOT NULL DEFAULT '{}');

CREATE OR REPLACE FUNCTION public.tax_owner_type(p_entity_type public.tax_entity_type) RETURNS public.financial_owner_type LANGUAGE sql IMMUTABLE AS $$ SELECT CASE p_entity_type WHEN 'player' THEN 'player'::public.financial_owner_type WHEN 'band' THEN 'band'::public.financial_owner_type WHEN 'company' THEN 'company'::public.financial_owner_type WHEN 'venue' THEN 'venue'::public.financial_owner_type WHEN 'city_government' THEN 'city'::public.financial_owner_type WHEN 'national_government' THEN 'country'::public.financial_owner_type ELSE 'system'::public.financial_owner_type END $$;
CREATE OR REPLACE FUNCTION public.tax_round_amount(p_amount numeric) RETURNS bigint LANGUAGE sql IMMUTABLE AS $$ SELECT GREATEST(0, floor(p_amount + 0.5))::bigint $$;
CREATE OR REPLACE FUNCTION public.calculate_progressive_personal_tax(p_jurisdiction_id uuid, p_taxable_income_minor bigint, p_as_of date DEFAULT CURRENT_DATE) RETURNS jsonb LANGUAGE plpgsql STABLE SET search_path=public AS $$
DECLARE b record; slice bigint; tax bigint := 0; lines jsonb := '[]'::jsonb;
BEGIN
  IF p_taxable_income_minor <= 0 THEN RETURN jsonb_build_object('taxMinor',0,'brackets','[]'::jsonb); END IF;
  FOR b IN SELECT * FROM public.personal_income_tax_brackets WHERE jurisdiction_id=p_jurisdiction_id AND status='active' AND effective_start_date<=p_as_of AND (effective_end_date IS NULL OR effective_end_date>=p_as_of) ORDER BY bracket_order LOOP
    slice := GREATEST(0, LEAST(p_taxable_income_minor, COALESCE(b.upper_bound_minor, p_taxable_income_minor)) - b.lower_bound_minor);
    IF slice > 0 THEN tax := tax + public.tax_round_amount(slice * b.tax_rate_basis_points / 10000.0); lines := lines || jsonb_build_array(jsonb_build_object('lower',b.lower_bound_minor,'upper',b.upper_bound_minor,'rateBasisPoints',b.tax_rate_basis_points,'taxableSliceMinor',slice)); END IF;
  END LOOP;
  RETURN jsonb_build_object('taxMinor',tax,'brackets',lines,'method','progressive');
END $$;

CREATE OR REPLACE FUNCTION public.ensure_country_economy_foundations() RETURNS integer LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$
DECLARE r record; cp uuid; juris uuid; acct public.financial_accounts; n integer := 0; pop bigint; code text; cname text;
BEGIN
  FOR r IN SELECT country, COUNT(*) city_count, COALESCE(SUM(population),0) population FROM public.cities GROUP BY country LOOP
    code := upper(regexp_replace(COALESCE(NULLIF(r.country,''),'UNK'),'[^A-Za-z]','','g')); code := substr(code || 'XXX',1,3); cname := COALESCE(NULLIF(r.country,''),'Unknown'); pop := GREATEST(COALESCE(r.population,0), r.city_count * 100000);
    INSERT INTO public.country_economic_profiles(country_name,country_code,population_placeholder,economic_size,economic_scale,economic_profile,prosperity_index,national_cost_index,national_wage_index,consumer_spending_index,tourism_index,music_industry_index,infrastructure_index,configuration_metadata)
    SELECT cname, code, pop, pop * 100,
      CASE WHEN pop>=50000000 THEN 'global'::public.country_economic_scale WHEN pop>=20000000 THEN 'major'::public.country_economic_scale WHEN pop>=8000000 THEN 'large'::public.country_economic_scale WHEN pop>=2000000 THEN 'medium'::public.country_economic_scale ELSE 'small'::public.country_economic_scale END,
      CASE WHEN avg_city.music_scene IS NULL THEN 'service_led_economy'::public.country_economic_profile_type WHEN avg_city.music_scene >= 70 THEN 'creative_industry_hub'::public.country_economic_profile_type ELSE 'service_led_economy'::public.country_economic_profile_type END,
      LEAST(160,90+(pop/10000000)::int*4), LEAST(170,90+(pop/10000000)::int*3), LEAST(165,92+(pop/10000000)::int*3), 100, 90 + (r.city_count::int % 30), 90 + (COALESCE(avg_city.music_scene,50)::int/5), 100,
      jsonb_build_object('seed','Finance Phase 5 country foundation','source','cities aggregation','baseline',100)
    FROM (SELECT AVG(music_scene) music_scene FROM public.cities WHERE country=r.country) avg_city
    ON CONFLICT(country_code) DO UPDATE SET country_name=EXCLUDED.country_name RETURNING id INTO cp;
    IF cp IS NULL THEN SELECT id INTO cp FROM public.country_economic_profiles WHERE country_code=code; END IF;
    acct := public.get_or_create_primary_financial_account('country', cp, cname || ' national treasury', 'USD');
    INSERT INTO public.national_treasury_profiles(country_profile_id,treasury_account_id,currency_code) VALUES(cp,acct.id,'USD') ON CONFLICT(country_profile_id) DO NOTHING;
    INSERT INTO public.tax_jurisdictions(country_profile_id,jurisdiction_name,jurisdiction_code,currency_code,status,metadata) VALUES(cp,cname || ' National Tax Jurisdiction', code || '-NAT','USD','active',jsonb_build_object('default',true,'phase','finance_phase5')) ON CONFLICT(jurisdiction_code) DO UPDATE SET status='active' RETURNING id INTO juris;
    UPDATE public.country_economic_profiles SET default_tax_jurisdiction_id=juris WHERE id=cp AND default_tax_jurisdiction_id IS NULL;
    INSERT INTO public.personal_tax_allowances(jurisdiction_id,allowance_type,amount_minor) VALUES(juris,'basic_tax_free_allowance',1000000) ON CONFLICT DO NOTHING;
    INSERT INTO public.personal_income_tax_brackets(jurisdiction_id,lower_bound_minor,upper_bound_minor,tax_rate_basis_points,bracket_order) VALUES(juris,0,1000000,0,1),(juris,1000000,5000000,1000,2),(juris,5000000,15000000,2000,3),(juris,15000000,NULL,3000,4) ON CONFLICT DO NOTHING;
    INSERT INTO public.corporation_tax_rules(jurisdiction_id,flat_rate_basis_points,small_profit_rate_basis_points,small_profit_threshold_minor,startup_allowance_minor) VALUES(juris,2000,1200,5000000,0) ON CONFLICT DO NOTHING;
    INSERT INTO public.sales_tax_rules(jurisdiction_id,standard_rate_basis_points,reduced_rate_basis_points,city_allocation_basis_points) VALUES(juris,800,400,2000) ON CONFLICT DO NOTHING;
    n := n + 1;
  END LOOP;
  RETURN n;
END $$;

CREATE OR REPLACE FUNCTION public.seed_tax_transaction_classifications() RETURNS integer LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$
BEGIN
  INSERT INTO public.tax_transaction_classifications(transaction_category,tax_category,affected_entity_types,is_taxable,income_or_expense_treatment,deductibility,withholding_eligible,sales_tax_treatment,jurisdiction_source,reporting_label) VALUES
  ('wage_payment','wages',ARRAY['player']::public.tax_entity_type[],true,'income','none',true,'out_of_scope','tax_residence','Wages'),('gig_payment','gig_earnings',ARRAY['player','band']::public.tax_entity_type[],true,'income','none',false,'out_of_scope','transaction_location','Gig earnings'),('streaming_royalty','royalties',ARRAY['player','band']::public.tax_entity_type[],true,'income','none',false,'out_of_scope','tax_residence','Royalties and streaming'),('dividend','dividends',ARRAY['player']::public.tax_entity_type[],true,'income','none',true,'out_of_scope','tax_residence','Dividends'),('band_contribution','member_contributions',ARRAY['band']::public.tax_entity_type[],false,'transfer','none',false,'out_of_scope','registration_country','Member contributions'),('owner_investment','owner_investment',ARRAY['company']::public.tax_entity_type[],false,'capital','none',false,'out_of_scope','registration_country','Owner investment'),('owner_withdrawal','owner_withdrawal',ARRAY['company']::public.tax_entity_type[],false,'capital','none',false,'out_of_scope','registration_country','Owner withdrawal'),('company_revenue','operating_revenue',ARRAY['company']::public.tax_entity_type[],true,'income','none',false,'standard','seller_location','Company revenue'),('product_sale','product_sales',ARRAY['company']::public.tax_entity_type[],true,'income','none',false,'standard','seller_location','Product sales'),('service_sale','service_sales',ARRAY['company']::public.tax_entity_type[],true,'income','none',false,'standard','seller_location','Service sales'),('payroll','payroll_expense',ARRAY['company']::public.tax_entity_type[],false,'expense','deductible',false,'out_of_scope','registration_country','Payroll'),('rent','rent_expense',ARRAY['player','company']::public.tax_entity_type[],false,'expense','controlled',false,'out_of_scope','tax_residence','Rent'),('utilities','utilities',ARRAY['company']::public.tax_entity_type[],false,'expense','deductible',false,'out_of_scope','registration_country','Utilities'),('maintenance','maintenance',ARRAY['company']::public.tax_entity_type[],false,'expense','deductible',false,'out_of_scope','registration_country','Maintenance'),('marketing','marketing',ARRAY['company']::public.tax_entity_type[],false,'expense','deductible',false,'out_of_scope','registration_country','Marketing'),('professional_services','professional_services',ARRAY['player','company']::public.tax_entity_type[],false,'expense','controlled',false,'standard','seller_location','Professional services'),('equipment_purchase','equipment',ARRAY['player','company']::public.tax_entity_type[],false,'expense','controlled',false,'standard','buyer_location','Equipment'),('refund','refunds',ARRAY['player','band','company']::public.tax_entity_type[],false,'excluded','none',false,'reverse_original','configured_default','Refunds'),('tax_withholding','withholding',ARRAY['player']::public.tax_entity_type[],false,'excluded','none',false,'out_of_scope','tax_residence','Tax withheld'),('tax_placeholder','legacy_tax_placeholder',ARRAY['player','band','company']::public.tax_entity_type[],false,'excluded','none',false,'out_of_scope','configured_default','Legacy tax placeholder') ON CONFLICT DO NOTHING;
  RETURN 1;
END $$;

CREATE OR REPLACE FUNCTION public.tax_assess_entity(p_entity_type public.tax_entity_type, p_entity_id uuid, p_tax_type public.tax_type, p_period_start date, p_period_end date, p_finalise boolean DEFAULT false) RETURNS uuid LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$
DECLARE reg record; per uuid; ass uuid; gross bigint:=0; deductions bigint:=0; withheld bigint:=0; paid bigint:=0; allowance bigint:=0; adjusted bigint:=0; calc jsonb; tax bigint:=0; due bigint:=0; refund bigint:=0; acct uuid;
BEGIN
  SELECT r.*, j.country_profile_id INTO reg FROM public.tax_entity_registrations r JOIN public.tax_jurisdictions j ON j.id=r.jurisdiction_id WHERE r.entity_type=p_entity_type AND r.entity_id=p_entity_id AND r.registration_status='active' AND r.effective_start<=p_period_end AND (r.effective_end IS NULL OR r.effective_end>=p_period_start) ORDER BY r.effective_start DESC LIMIT 1;
  IF reg.id IS NULL THEN RAISE EXCEPTION 'missing tax registration for % %', p_entity_type, p_entity_id; END IF;
  INSERT INTO public.tax_periods(entity_type,entity_id,jurisdiction_id,tax_type,period_start,period_end,filing_due_date,payment_due_date,status) VALUES(p_entity_type,p_entity_id,reg.jurisdiction_id,p_tax_type,p_period_start,p_period_end,p_period_end+14,p_period_end+14,CASE WHEN p_finalise THEN 'ready_to_file'::public.tax_period_status ELSE 'estimated' END) ON CONFLICT(entity_type,entity_id,jurisdiction_id,tax_type,period_start,period_end) DO UPDATE SET status=EXCLUDED.status RETURNING id INTO per;
  SELECT id INTO acct FROM public.financial_accounts WHERE owner_type=public.tax_owner_type(p_entity_type) AND owner_id=p_entity_id AND is_primary LIMIT 1;
  SELECT COALESCE(SUM(CASE WHEN t.destination_account_id=acct AND c.is_taxable AND c.income_or_expense_treatment='income' THEN t.net_amount_minor ELSE 0 END),0), COALESCE(SUM(CASE WHEN t.source_account_id=acct AND c.deductibility IN ('deductible','controlled') THEN t.net_amount_minor ELSE 0 END),0), COALESCE(SUM(CASE WHEN t.source_account_id=acct AND t.transaction_category IN ('tax_withholding','payroll_tax_withholding') THEN t.net_amount_minor ELSE 0 END),0)
  INTO gross,deductions,withheld FROM public.financial_transactions t LEFT JOIN public.tax_transaction_classifications c ON c.transaction_category=t.transaction_category AND t.created_at::date BETWEEN c.effective_start_date AND COALESCE(c.effective_end_date,'9999-12-31') WHERE t.status='completed' AND t.created_at::date BETWEEN p_period_start AND p_period_end AND acct IS NOT NULL AND (t.source_account_id=acct OR t.destination_account_id=acct);
  IF p_tax_type='personal_income' THEN SELECT COALESCE(SUM(amount_minor),0) INTO allowance FROM public.personal_tax_allowances WHERE jurisdiction_id=reg.jurisdiction_id AND status='active' AND effective_start_date<=p_period_end AND (effective_end_date IS NULL OR effective_end_date>=p_period_start); adjusted := GREATEST(0,gross-deductions-allowance); calc := public.calculate_progressive_personal_tax(reg.jurisdiction_id,adjusted,p_period_end); tax := (calc->>'taxMinor')::bigint; ELSE adjusted := GREATEST(0,gross-deductions); SELECT public.tax_round_amount(adjusted * COALESCE((SELECT flat_rate_basis_points FROM public.corporation_tax_rules WHERE jurisdiction_id=reg.jurisdiction_id AND status='active' ORDER BY effective_start_date DESC LIMIT 1),2000) / 10000.0) INTO tax; calc := jsonb_build_object('method','flat','taxMinor',tax); END IF;
  SELECT COALESCE(SUM(amount_minor),0) INTO paid FROM public.tax_payments WHERE assessment_id IN (SELECT id FROM public.tax_assessments WHERE tax_period_id=per);
  due := GREATEST(0,tax-withheld-paid); refund := GREATEST(0,withheld+paid-tax);
  INSERT INTO public.tax_assessments(entity_type,entity_id,jurisdiction_id,tax_type,tax_period_id,gross_taxable_amount_minor,allowances_minor,deductions_minor,adjusted_taxable_amount_minor,calculated_tax_minor,withheld_tax_minor,prior_payments_minor,final_amount_due_minor,refund_due_minor,calculation_breakdown,status,finalised_at) VALUES(p_entity_type,p_entity_id,reg.jurisdiction_id,p_tax_type,per,gross,allowance,deductions,adjusted,tax,withheld,paid,due,refund,calc,CASE WHEN p_finalise THEN CASE WHEN due>0 THEN 'payment_due'::public.tax_assessment_status WHEN refund>0 THEN 'refund_due' ELSE 'finalised' END ELSE 'estimate' END,CASE WHEN p_finalise THEN timezone('utc',now()) ELSE NULL END) RETURNING id INTO ass;
  INSERT INTO public.tax_statement_lines(assessment_id,reporting_label,gross_amount_minor,taxable_amount_minor,deductible_amount_minor,withheld_amount_minor,explanation) VALUES(ass,'Ledger-backed taxable activity',gross,adjusted,deductions,withheld,'Calculated from completed financial ledger transactions in the period.');
  RETURN ass;
END $$;

CREATE OR REPLACE FUNCTION public.tax_pay_assessment(p_assessment_id uuid, p_amount_minor bigint, p_idempotency_key text) RETURNS uuid LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$
DECLARE a record; country uuid; tx uuid; pay_total bigint;
BEGIN
  SELECT * INTO a FROM public.tax_assessments WHERE id=p_assessment_id FOR UPDATE; IF a.id IS NULL THEN RAISE EXCEPTION 'assessment not found'; END IF; IF p_amount_minor <= 0 OR p_amount_minor > a.final_amount_due_minor THEN RAISE EXCEPTION 'invalid payment amount'; END IF;
  SELECT j.country_profile_id INTO country FROM public.tax_jurisdictions j WHERE j.id=a.jurisdiction_id;
  SELECT public.finance_transfer(public.tax_owner_type(a.entity_type),a.entity_id,'country',country,p_amount_minor,'national_tax_payment','Tax assessment payment',p_idempotency_key,'tax_assessment',a.id,NULL,jsonb_build_object('taxType',a.tax_type)) INTO tx;
  INSERT INTO public.tax_payments(assessment_id,payer_entity_type,payer_entity_id,treasury_country_profile_id,amount_minor,transaction_id,idempotency_key) VALUES(a.id,a.entity_type,a.entity_id,country,p_amount_minor,tx,p_idempotency_key) ON CONFLICT(idempotency_key) DO NOTHING;
  UPDATE public.national_treasury_profiles SET tax_revenue_minor=tax_revenue_minor+p_amount_minor, updated_at=timezone('utc',now()) WHERE country_profile_id=country;
  SELECT COALESCE(SUM(amount_minor),0) INTO pay_total FROM public.tax_payments WHERE assessment_id=a.id;
  UPDATE public.tax_assessments SET prior_payments_minor=pay_total, final_amount_due_minor=GREATEST(0,calculated_tax_minor-withheld_tax_minor-pay_total), status=CASE WHEN GREATEST(0,calculated_tax_minor-withheld_tax_minor-pay_total)=0 THEN 'paid'::public.tax_assessment_status ELSE 'partially_paid' END WHERE id=a.id;
  RETURN tx;
END $$;

CREATE OR REPLACE FUNCTION public.tax_refund_assessment(p_assessment_id uuid, p_idempotency_key text) RETURNS uuid LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$
DECLARE a record; country uuid; tx uuid;
BEGIN
  SELECT * INTO a FROM public.tax_assessments WHERE id=p_assessment_id FOR UPDATE; IF a.id IS NULL THEN RAISE EXCEPTION 'assessment not found'; END IF; IF a.refund_due_minor <= 0 THEN RAISE EXCEPTION 'no refund due'; END IF;
  SELECT j.country_profile_id INTO country FROM public.tax_jurisdictions j WHERE j.id=a.jurisdiction_id;
  SELECT public.finance_transfer('country',country,public.tax_owner_type(a.entity_type),a.entity_id,a.refund_due_minor,'national_tax_refund','Tax assessment refund',p_idempotency_key,'tax_assessment',a.id,NULL,jsonb_build_object('taxType',a.tax_type)) INTO tx;
  INSERT INTO public.tax_refunds(assessment_id,recipient_entity_type,recipient_entity_id,treasury_country_profile_id,amount_minor,transaction_id,idempotency_key,status,paid_at) VALUES(a.id,a.entity_type,a.entity_id,country,a.refund_due_minor,tx,p_idempotency_key,'paid',timezone('utc',now())) ON CONFLICT(idempotency_key) DO NOTHING;
  UPDATE public.national_treasury_profiles SET refunds_minor=refunds_minor+a.refund_due_minor, updated_at=timezone('utc',now()) WHERE country_profile_id=country;
  UPDATE public.tax_assessments SET refunds_minor=refund_due_minor, refund_due_minor=0, status='refunded' WHERE id=a.id;
  RETURN tx;
END $$;

CREATE OR REPLACE FUNCTION public.tax_calculate_sales_tax(p_jurisdiction_id uuid, p_category public.financial_transaction_category, p_base_amount_minor bigint, p_pricing_mode text DEFAULT NULL) RETURNS jsonb LANGUAGE plpgsql STABLE SET search_path=public AS $$
DECLARE r record; rate integer:=0; mode text; tax bigint; net bigint; total bigint;
BEGIN
  SELECT * INTO r FROM public.sales_tax_rules WHERE jurisdiction_id=p_jurisdiction_id AND status='active' AND CURRENT_DATE BETWEEN effective_start_date AND COALESCE(effective_end_date,'9999-12-31') ORDER BY effective_start_date DESC LIMIT 1;
  mode := COALESCE(p_pricing_mode,r.pricing_mode,'exclusive'); IF p_category::text = ANY(COALESCE(r.exempt_categories,'{}')) THEN rate:=0; ELSIF p_category::text = ANY(COALESCE(r.zero_rated_categories,'{}')) THEN rate:=0; ELSIF p_category::text = ANY(COALESCE(r.taxable_categories,'{}')) THEN rate:=COALESCE(r.standard_rate_basis_points,0); ELSE rate:=0; END IF;
  IF mode='inclusive' AND rate>0 THEN total:=p_base_amount_minor; net:=public.tax_round_amount(p_base_amount_minor * 10000.0/(10000+rate)); tax:=total-net; ELSE net:=p_base_amount_minor; tax:=public.tax_round_amount(p_base_amount_minor*rate/10000.0); total:=net+tax; END IF;
  RETURN jsonb_build_object('baseAmountMinor',net,'taxAmountMinor',tax,'totalAmountMinor',total,'rateBasisPoints',rate,'pricingMode',mode,'settlementModel','immediate_remittance','rounding','nearest minor unit');
END $$;

CREATE OR REPLACE FUNCTION public.tax_mark_overdue(p_as_of date DEFAULT CURRENT_DATE) RETURNS integer LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE n integer; BEGIN UPDATE public.tax_assessments a SET status='overdue' FROM public.tax_periods p WHERE p.id=a.tax_period_id AND a.status IN ('payment_due','partially_paid','filed') AND p.payment_due_date < p_as_of AND a.final_amount_due_minor > 0; GET DIAGNOSTICS n = ROW_COUNT; UPDATE public.tax_periods SET status='overdue' WHERE payment_due_date < p_as_of AND status IN ('payment_due','partially_paid','filed','ready_to_file'); RETURN n; END $$;

CREATE OR REPLACE VIEW public.country_economy_public_view AS SELECT cp.id country_profile_id, cp.country_name, cp.country_code, cp.primary_currency_code, cp.population_placeholder, cp.economic_scale, cp.economic_profile, cp.prosperity_index, cp.national_cost_index, cp.national_wage_index, cp.consumer_spending_index, cp.business_confidence_index, cp.tourism_index, cp.infrastructure_index, cp.music_industry_index, cp.employment_index, cp.tax_burden_index, cp.government_spending_index, cp.economic_trend, fa.current_balance_minor treasury_balance_minor, nt.tax_revenue_minor, nt.government_spending_minor FROM public.country_economic_profiles cp LEFT JOIN public.national_treasury_profiles nt ON nt.country_profile_id=cp.id LEFT JOIN public.financial_accounts fa ON fa.id=nt.treasury_account_id AND nt.public_summary_enabled;
CREATE OR REPLACE VIEW public.tax_integrity_issues AS SELECT 'missing_country_profile' issue_type, c.country subject_id FROM (SELECT DISTINCT country FROM public.cities) c LEFT JOIN public.country_economic_profiles cp ON cp.country_name=c.country WHERE cp.id IS NULL UNION ALL SELECT 'missing_national_treasury', cp.id::text FROM public.country_economic_profiles cp LEFT JOIN public.national_treasury_profiles nt ON nt.country_profile_id=cp.id WHERE nt.country_profile_id IS NULL UNION ALL SELECT 'missing_default_jurisdiction', cp.id::text FROM public.country_economic_profiles cp WHERE cp.default_tax_jurisdiction_id IS NULL UNION ALL SELECT 'country_without_active_jurisdiction', cp.id::text FROM public.country_economic_profiles cp WHERE NOT EXISTS (SELECT 1 FROM public.tax_jurisdictions j WHERE j.country_profile_id=cp.id AND j.status='active') UNION ALL SELECT 'final_assessment_without_statement', a.id::text FROM public.tax_assessments a WHERE a.status NOT IN ('estimate','draft') AND NOT EXISTS (SELECT 1 FROM public.tax_statement_lines l WHERE l.assessment_id=a.id);

ALTER TABLE public.country_economic_profiles ENABLE ROW LEVEL SECURITY; ALTER TABLE public.national_treasury_profiles ENABLE ROW LEVEL SECURITY; ALTER TABLE public.tax_jurisdictions ENABLE ROW LEVEL SECURITY; ALTER TABLE public.tax_entity_registrations ENABLE ROW LEVEL SECURITY; ALTER TABLE public.tax_transaction_classifications ENABLE ROW LEVEL SECURITY; ALTER TABLE public.personal_income_tax_brackets ENABLE ROW LEVEL SECURITY; ALTER TABLE public.personal_tax_allowances ENABLE ROW LEVEL SECURITY; ALTER TABLE public.corporation_tax_rules ENABLE ROW LEVEL SECURITY; ALTER TABLE public.company_tax_losses ENABLE ROW LEVEL SECURITY; ALTER TABLE public.sales_tax_rules ENABLE ROW LEVEL SECURITY; ALTER TABLE public.tax_periods ENABLE ROW LEVEL SECURITY; ALTER TABLE public.tax_assessments ENABLE ROW LEVEL SECURITY; ALTER TABLE public.tax_payments ENABLE ROW LEVEL SECURITY; ALTER TABLE public.tax_refunds ENABLE ROW LEVEL SECURITY; ALTER TABLE public.tax_statement_lines ENABLE ROW LEVEL SECURITY; ALTER TABLE public.band_tax_allocations ENABLE ROW LEVEL SECURITY; ALTER TABLE public.tax_audit_events ENABLE ROW LEVEL SECURITY;
CREATE POLICY country_economic_profiles_public_select ON public.country_economic_profiles FOR SELECT USING (true); CREATE POLICY national_treasury_profiles_public_select ON public.national_treasury_profiles FOR SELECT USING (public_summary_enabled); CREATE POLICY tax_jurisdictions_public_select ON public.tax_jurisdictions FOR SELECT USING (status='active'); CREATE POLICY tax_classifications_public_select ON public.tax_transaction_classifications FOR SELECT USING (true); CREATE POLICY personal_brackets_public_select ON public.personal_income_tax_brackets FOR SELECT USING (status='active'); CREATE POLICY personal_allowances_public_select ON public.personal_tax_allowances FOR SELECT USING (status='active'); CREATE POLICY corporation_rules_public_select ON public.corporation_tax_rules FOR SELECT USING (status='active'); CREATE POLICY sales_tax_rules_public_select ON public.sales_tax_rules FOR SELECT USING (status='active');
CREATE POLICY tax_registrations_owner_select ON public.tax_entity_registrations FOR SELECT USING ((entity_type='player' AND EXISTS (SELECT 1 FROM public.profiles p WHERE p.id=entity_id AND p.user_id=auth.uid())) OR (entity_type='band' AND EXISTS (SELECT 1 FROM public.band_members bm JOIN public.profiles p ON p.id=bm.profile_id WHERE bm.band_id=entity_id AND p.user_id=auth.uid())) OR (entity_type='company' AND EXISTS (SELECT 1 FROM public.companies c WHERE c.id=entity_id AND c.owner_id=auth.uid())));
CREATE POLICY tax_periods_owner_select ON public.tax_periods FOR SELECT USING (EXISTS (SELECT 1 FROM public.tax_entity_registrations r WHERE r.entity_type=tax_periods.entity_type AND r.entity_id=tax_periods.entity_id));
CREATE POLICY tax_assessments_owner_select ON public.tax_assessments FOR SELECT USING (EXISTS (SELECT 1 FROM public.tax_periods p WHERE p.id=tax_period_id));
CREATE POLICY tax_statement_lines_owner_select ON public.tax_statement_lines FOR SELECT USING (EXISTS (SELECT 1 FROM public.tax_assessments a WHERE a.id=assessment_id));

SELECT public.ensure_country_economy_foundations();
SELECT public.seed_tax_transaction_classifications();
